options.elementValueChanged:
const el = context.element;

if (el.id !== 'device_id') {
  return;
}

const id = el.value;

if (!id) {
  // Cleared back to "add new" -- don't leave a previous device's data sitting
  // in the other fields.
  context.panel.patchFormValue({
    ip_address: '',
    hostname: '',
    snmp_version: '',
    group_name: '',
    v3_user: '',
    v3_auth_protocol: '',
    v3_priv_protocol: '',
  });
  return;
}

fetch(`http://localhost:8080/devices/${id}`)
  .then((resp) => {
    if (!resp.ok) {
      throw new Error(`HTTP ${resp.status}`);
    }
    return resp.json();
  })
  .then((d) => {
    context.panel.patchFormValue({
      ip_address: d.ip_address || '',
      hostname: d.hostname || '',
      snmp_version: d.snmp_version || '',
      group_name: d.group_name || '',
      v3_user: d.v3_user || '',
      v3_auth_protocol: d.v3_auth_protocol || '',
      v3_priv_protocol: d.v3_priv_protocol || '',
    });
    context.grafana.notifySuccess(['Loaded', `Loaded device #${id}: ${d.ip_address} (status: ${d.status}). Credential fields are left blank -- only fill them in if you want to change them.`]);
  })
  .catch((err) => {
    context.grafana.notifyError(['Error', `Could not load device #${id}: ${err}. Check the ID in the Devices table below -- this field takes the numeric ID, not the IP address.`]);
  });

elements.customCode:
const elements = context.panel.elements;
const idEl = elements.find((e) => e.id === 'device_id');
const id = idEl ? idEl.value : 0;

if (!id) {
  context.grafana.notifyError(['Error', 'Enter a Device ID above before deleting -- there is nothing to delete.']);
  return;
}

if (!window.confirm(`Delete device #${id}? This cannot be undone.`)) {
  return;
}

fetch(`http://localhost:8080/devices/${id}`, { method: 'DELETE' })
  .then((resp) => {
    if (resp.ok) {
      context.grafana.notifySuccess(['Deleted', `Device #${id} deleted.`]);
      context.panel.patchFormValue({
        device_id: 0,
        ip_address: '',
        hostname: '',
        snmp_version: '',
        group_name: '',
        v3_user: '',
        v3_auth_protocol: '',
        v3_priv_protocol: '',
      });
      context.grafana.refresh();
    } else {
      context.grafana.notifyError(['Error', `Failed to delete device: HTTP ${resp.status}`]);
    }
  })
  .catch((err) => {
    context.grafana.notifyError(['Error', `Failed to delete device: ${err}`]);
  });

update.code:
const elements = context.panel.elements;
const get = (id) => {
  const el = elements.find((e) => e.id === id);
  return el && el.value !== undefined && el.value !== null ? el.value : '';
};

const deviceId = get('device_id');
const isEdit = !!deviceId;

if (!isEdit && !get('ip_address')) {
  context.grafana.notifyError(['Error', 'IP Address is required to add a new device.']);
  return;
}

const payload = {
  ip_address: get('ip_address'),
  hostname: get('hostname'),
  snmp_version: get('snmp_version'),
  group_name: get('group_name'),
  v3_user: get('v3_user'),
  v3_auth_protocol: get('v3_auth_protocol'),
  v3_priv_protocol: get('v3_priv_protocol'),
};

// Only send credential fields if the user actually typed something -- leaving
// them blank while editing must not overwrite the stored credential.
const community = get('community');
const v3AuthKey = get('v3_auth_key');
const v3PrivKey = get('v3_priv_key');
if (!isEdit || community) payload.community = community;
if (!isEdit || v3AuthKey) payload.v3_auth_key = v3AuthKey;
if (!isEdit || v3PrivKey) payload.v3_priv_key = v3PrivKey;

const url = isEdit ? `http://localhost:8080/devices/${deviceId}` : 'http://localhost:8080/devices';
const method = isEdit ? 'PATCH' : 'POST';

fetch(url, {
  method,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(payload),
})
  .then(async (resp) => {
    if (resp.ok) {
      const body = await resp.json();
      context.grafana.notifySuccess(['Saved', `Device ${body.ip_address} ${isEdit ? 'updated' : 'created'} -- status: ${body.status}.`]);
      context.panel.initialRequest();
      context.grafana.refresh();
    } else {
      const text = await resp.text().catch(() => '');
      context.grafana.notifyError(['Error', `Failed to save device: HTTP ${resp.status}. ${text}`]);
    }
  })
  .catch((err) => {
    context.grafana.notifyError(['Error', `Failed to save device: ${err}`]);
  });

if (context.panel.response && context.panel.response.ok) {
  context.grafana.notifySuccess(['Saved', 'Polling interval updated.']);
  context.panel.initialRequest();
  context.grafana.refresh();
} else {
  context.grafana.notifyError(['Error', 'Failed to update polling interval.']);
}
